<span class="line"><span style="color:#CDD6F4;">    batch </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">batches</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">retrieve</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">batch</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">id</span><span style="color:#9399B2;">)</span></span>
